def checkAdminPassword(password):
    if len(password) < 12:
        return False
    if not any(c.isupper() for c in password):
        return False
    if not any(c.islower() for c in password):
        return False
    if not any(c.isdigit() for c in password):
        return False
    special = set('!@#$%^&*()-_=+[]{}|;:\'"<>/?.~`')
    if not any(c in special for c in password):
        return False
    if ' ' in password:
        return False
    return True

